--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `users` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `surname` varchar(80) DEFAULT NULL,
  `first_name` varchar(80) DEFAULT NULL,
  `middle_initial` varchar(10) DEFAULT NULL,
  `name_suffix` varchar(20) DEFAULT NULL,
  `gender` varchar(20) DEFAULT NULL,
  `grade_level` varchar(20) DEFAULT NULL,
  `student_id` varchar(50) DEFAULT NULL,
  `birthdate` date DEFAULT NULL,
  `age` int(3) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `guardian_name` varchar(255) DEFAULT NULL,
  `guardian_contact` varchar(255) DEFAULT NULL,
  `email` varchar(191) NOT NULL,
  `contact_number` varchar(255) DEFAULT NULL,
  `bio` text DEFAULT NULL,
  `profile_photo` varchar(255) DEFAULT NULL,
  `username` varchar(50) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `password_history` text DEFAULT NULL,
  `role` varchar(50) DEFAULT NULL,
  `admin_privileges` text DEFAULT NULL,
  `mfa_enabled` tinyint(1) DEFAULT 0,
  `mfa_code` varchar(10) DEFAULT NULL,
  `mfa_expires_at` datetime DEFAULT NULL,
  `section_id` int(11) unsigned DEFAULT NULL,
  `guidance_flag` tinyint(1) NOT NULL DEFAULT 0,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `is_online` tinyint(1) DEFAULT 0,
  `last_seen_at` datetime DEFAULT NULL,
  `failed_attempts` int(11) NOT NULL DEFAULT 0,
  `last_failed_at` datetime DEFAULT NULL,
  `locked_until` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `email` (`email`),
  UNIQUE KEY `username` (`username`),
  KEY `fk_users_section` (`section_id`),
  CONSTRAINT `fk_users_section` FOREIGN KEY (`section_id`) REFERENCES `sections` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

